  ('elementary-8b44517b-moex-00147', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '上級政府或主管機關，對於下級政府或機關所陳報之事項，加以審查，並作成決定，以完成該事項之法定 效力。上級政府或主管機關之行為，稱為：', '["考核", "備查", "監督", "核定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00148', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列有關擴張與限縮解釋的敘述，何者錯誤？', '["擴張解釋與限縮解釋，都是以文義的可能範圍為界限", "憲法第8條人民身體之自由應予保障，所稱人民指自然人，即為限縮解釋", "處罰或課予人民義務之規定文字，應從嚴解釋，不得任意擴張", "例外規定應為擴張解釋，否則有失其規定之旨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00149', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者不是形成權？', '["甲、乙二人共有一筆土地，因協議分割不成，甲提起訴訟，請求法院為裁判分割", "甲售予車輛於乙，惟該車有瑕疵，乙向甲主張減少價金", "甲與乙成立買賣契約，甲未給付價金，15年後乙向甲請求給付價金，甲主張已超過15年，拒絕給付價金", "甲與乙成立買賣契約，但乙未於期限內給付，甲向乙解除契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00150', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '促進產業升級條例於民國99年5月12日公布廢止。關於該條例之廢止，下列敘述何者正確？', '["該條例之廢止，應經立法院通過，由立法院公布", "該條例之廢止，應經立法院通過，總統公布", "該條例之廢止，應由主管機關公布，並送立法院備查", "該條例於民國99年5月12日公布廢止時即失效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00151', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '下列何者為立法院通過，總統公布之法律？', '["財政部各地區國稅局組織通則", "內政部土地重劃工程處辦事細則", "工程施工查核小組組織準則", "不當黨產處理委員會組織規程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00152', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依司法院大法官解釋，關於法律保留原則，下列敘述何者正確？', '["對於人民生命之剝奪，應由憲法明文規範", "對於人民財產權之限制，僅能以法律為之", "對於人民入出境自由之限制，得由立法機關授權主管機關以命令限制之", "社會福利給付之資格、方式，皆非法律保留事項，行政機關得自行發布命令加以規範"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00153', 'elementary-8b44517b', 'elementary-8b44517b-moex-114-55d283b0', 'sub-elementary-8b44517b-04', NULL, 'single_choice', '依憲法及增修條文規定，下列何者之人事任命，應經立法院同意？', '["行政院院長", "行政院政務委員", "審計長", "司法院秘書長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:30+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "506", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
